unitsize(1.5mm);
defaultpen(linewidth(.7pt)+fontsize(10pt));
dotfactor=3;
pair A=(0,0), B=(13,0), C=(13,13), D=(0,13), E=(1+12/13,sqrt(5^2-(1+12/13)^2)), F=(1+12/13,0);
pair[] dots={A,B,C,D,E,F};
draw(A--B--C--D--cycle);
draw(A--E--B);
draw(E--F);
dot(dots);
label("A",A,SW);
label("B",B,SE);
label("C",C,NE);
label("D",D,NW);
label("E",E,N);
label("F",F,S);
[/asy]

